import { _ as _export_sfc, c as createElementBlock, o as openBlock, ag as createStaticVNode } from "./chunks/framework.9IhFZouV.js";
const __pageData = JSON.parse('{"title":"Conflict Handling","description":"","frontmatter":{},"headers":[],"relativePath":"flashql/conflicts.md","filePath":"flashql/conflicts.md"}');
const _sfc_main = { name: "flashql/conflicts.md" };
function _sfc_render(_ctx, _cache, $props, $setup, $data, $options) {
  return openBlock(), createElementBlock("div", null, [..._cache[0] || (_cache[0] = [
    createStaticVNode('<h1 id="conflict-handling" tabindex="-1">Conflict Handling <a class="header-anchor" href="#conflict-handling" aria-label="Permalink to &quot;Conflict Handling&quot;">​</a></h1><p>FlashQL sync is designed around predictable conflict behavior.</p><p>That does not mean every conflict is magically merged. It means the system has a clear model for when a local write can still be applied and when it has lost the race to newer authoritative state.</p><h2 id="start-with-the-intuition" tabindex="-1">Start with the intuition <a class="header-anchor" href="#start-with-the-intuition" aria-label="Permalink to &quot;Start with the intuition&quot;">​</a></h2><p>If two clients both edit the same row while offline, you do not want the later reconnect to silently overwrite the first one.</p><p>You want the system to say, in effect:</p><blockquote><p>&quot;apply this write only if the origin row is still the version I think it is&quot;</p></blockquote><p>That is the heart of FlashQL&#39;s conflict model.</p><h2 id="the-role-of-upstream-mvcc-key" tabindex="-1">The role of <code>upstream_mvcc_key</code> <a class="header-anchor" href="#the-role-of-upstream-mvcc-key" aria-label="Permalink to &quot;The role of `upstream_mvcc_key`&quot;">​</a></h2><p>For replicated writeable views, the main view-level knob is <code>upstream_mvcc_key</code>.</p><p>Example:</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">CREATE</span><span style="color:#BABED8;"> REALTIME VIEW public.users </span><span style="color:#F78C6C;">AS</span></span>\n<span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#89DDFF;"> *</span><span style="color:#F78C6C;"> FROM</span><span style="color:#BABED8;"> public.users</span></span>\n<span class="line"><span style="color:#F78C6C;">WITH</span><span style="color:#BABED8;"> (</span></span>\n<span class="line"><span style="color:#BABED8;">  replication_origin </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">postgres:primary</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">,</span></span>\n<span class="line"><span style="color:#BABED8;">  upstream_mvcc_key </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">XMIN</span><span style="color:#89DDFF;">&#39;</span></span>\n<span class="line"><span style="color:#BABED8;">);</span></span></code></pre></div><p>This tells FlashQL which origin-side version column or token should be used to condition outbound writes.</p><h2 id="what-that-means-practically" tabindex="-1">What that means practically <a class="header-anchor" href="#what-that-means-practically" aria-label="Permalink to &quot;What that means practically&quot;">​</a></h2><p>Without an origin version token, an outbound update may only be able to say:</p><blockquote><p>update row <code>id = 1</code></p></blockquote><p>With an origin version token, it can instead say:</p><blockquote><p>update row <code>id = 1</code> only if it is still version <code>13297</code></p></blockquote><p>That difference is what makes conflict handling predictable.</p><h2 id="defaults" tabindex="-1">Defaults <a class="header-anchor" href="#defaults" aria-label="Permalink to &quot;Defaults&quot;">​</a></h2><p>For PostgreSQL- and FlashQL-backed origins, FlashQL can often default <code>upstream_mvcc_key</code> to <code>XMIN</code> for updateable replicated views.</p><p>That gives a useful default conflict story without forcing every view definition to repeat it.</p><h2 id="what-a-conflict-usually-means" tabindex="-1">What a conflict usually means <a class="header-anchor" href="#what-a-conflict-usually-means" aria-label="Permalink to &quot;What a conflict usually means&quot;">​</a></h2><p>A conflict usually means one of these:</p><ul><li>another client already updated the row</li><li>another client already deleted the row</li><li>the origin row version no longer matches the local expectation</li></ul><p>So conflicts are expected sync outcomes, not mysterious transport failures.</p><h2 id="how-this-relates-to-write-policy" tabindex="-1">How this relates to write policy <a class="header-anchor" href="#how-this-relates-to-write-policy" aria-label="Permalink to &quot;How this relates to write policy&quot;">​</a></h2><p>Conflict detection works with both write policies, but the user experience differs.</p><h3 id="origin-first" tabindex="-1"><code>origin_first</code> <a class="header-anchor" href="#origin-first" aria-label="Permalink to &quot;`origin_first`&quot;">​</a></h3><ul><li>local writes queue outbound work</li><li>visible local state waits for authoritative inbound data</li><li>a conflicting outbound attempt can become <code>conflicted</code></li><li>inbound still brings the local row to the authoritative state</li></ul><h3 id="local-first" tabindex="-1"><code>local_first</code> <a class="header-anchor" href="#local-first" aria-label="Permalink to &quot;`local_first`&quot;">​</a></h3><ul><li>local writes stage visible row state immediately</li><li>the row carries <code>__staged = true</code></li><li>a conflicting outbound attempt can become <code>conflicted</code></li><li>inbound later normalizes the row back to authoritative state</li></ul><p>So in both models:</p><ul><li>queue state tells you what happened to the outbound attempt</li><li>inbound origin data restores authoritative row state</li></ul><h2 id="the-main-conflict-scenarios" tabindex="-1">The main conflict scenarios <a class="header-anchor" href="#the-main-conflict-scenarios" aria-label="Permalink to &quot;The main conflict scenarios&quot;">​</a></h2><p>These are the core cases to keep in mind.</p><h3 id="update-vs-update" tabindex="-1">update vs update <a class="header-anchor" href="#update-vs-update" aria-label="Permalink to &quot;update vs update&quot;">​</a></h3><ul><li>two offline clients both update the same row</li><li>the first reconnect to apply upstream wins</li><li>the second reconnect conflicts</li><li>inbound catches both clients up to the winner&#39;s state</li></ul><h3 id="delete-vs-update" tabindex="-1">delete vs update <a class="header-anchor" href="#delete-vs-update" aria-label="Permalink to &quot;delete vs update&quot;">​</a></h3><ul><li>one client deletes while offline</li><li>another updates the row and reconnects first</li><li>the later delete can conflict</li><li>inbound restores the updated authoritative row</li></ul><h3 id="update-vs-delete" tabindex="-1">update vs delete <a class="header-anchor" href="#update-vs-delete" aria-label="Permalink to &quot;update vs delete&quot;">​</a></h3><ul><li>one client updates while offline</li><li>another deletes the row and reconnects first</li><li>the later update can conflict</li><li>inbound removes the row locally</li></ul><p>These cases have been exercised in real stack tests.</p><h2 id="observable-conflict-behavior" tabindex="-1">Observable conflict behavior <a class="header-anchor" href="#observable-conflict-behavior" aria-label="Permalink to &quot;Observable conflict behavior&quot;">​</a></h2><p><code>db.sync</code> emits a dedicated <code>conflict</code> event for these cases.</p><p>That lets applications observe conflict as its own operational category instead of treating it as a generic network error.</p><p>Queue rows can also end up with:</p><ul><li><code>status = &#39;conflicted&#39;</code></li></ul><p>which is useful for inspection and debugging.</p><h2 id="what-conflict-handling-is-not-claiming" tabindex="-1">What conflict handling is not claiming <a class="header-anchor" href="#what-conflict-handling-is-not-claiming" aria-label="Permalink to &quot;What conflict handling is not claiming&quot;">​</a></h2><p>FlashQL is not currently claiming:</p><ul><li>arbitrary semantic merges</li><li>domain-specific reconciliation logic</li><li>that every possible view shape is safely writable</li></ul><p>The strong claim is narrower and more useful:</p><ul><li>when a replicated writable view has a usable origin version token, FlashQL can detect and classify write races predictably</li></ul><h2 id="related-docs" tabindex="-1">Related docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related docs&quot;">​</a></h2><ul><li><a href="/flashql/foreign-io">Federation, Materialization, Realtime Views, and Write Paths</a></li><li><a href="/flashql/sync">FlashQL Sync</a></li><li><a href="/flashql/sync-patterns">Sync Integration Patterns</a></li></ul>', 56)
  ])]);
}
const conflicts = /* @__PURE__ */ _export_sfc(_sfc_main, [["render", _sfc_render]]);
